    into params_array
    from jsonb_each_text(params);

    -- Add to the request queue
    values (
        ''GET'',
        net._encode_url_with_params_array(url, params_array),
        headers,
        timeout_milliseconds
    )
    returning id
    into request_id;

    perform net.wake();

    return request_id;
end
