DECLARE
  v_team_name       text;
  v_captain_name    text;
  v_captain_email   text;
  v_tournament_name text;
  v_start_date      text;
  v_notes           text;
  v_tournament_id   uuid;
BEGIN
  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status NOT IN (''APPROVED'', ''REJECTED'') THEN RETURN NEW; END IF;
  v_tournament_id := NEW.tournament_id;
  SELECT name INTO v_team_name FROM public.teams WHERE id = NEW.team_id;
  SELECT name, start_date::text INTO v_tournament_name, v_start_date
  FROM public.tournaments WHERE id = v_tournament_id;
  SELECT p.full_name, p.email INTO v_captain_name, v_captain_email
  FROM public.profiles p WHERE p.id = NEW.user_id;
  v_notes := NEW.notes;
  IF v_captain_email IS NOT NULL THEN
    PERFORM public.call_edge_function(''send-email'', jsonb_build_object(
      ''type'', CASE NEW.status WHEN ''APPROVED'' THEN ''inscricao_aprovada'' ELSE ''inscricao_rejeitada'' END,
      ''to'', v_captain_email,
      ''data'', jsonb_build_object(
        ''captain_name'', v_captain_name, ''team_name'', v_team_name,
        ''tournament_name'', v_tournament_name, ''start_date'', v_start_date, ''notes'', v_notes
      )
    ));
  END IF;
  PERFORM public.call_edge_function(''discord-webhook'', jsonb_build_object(
    ''type'', CASE NEW.status WHEN ''APPROVED'' THEN ''inscricao_aprovada'' ELSE ''inscricao_rejeitada'' END,
    ''tournament_id'', v_tournament_id::text,
    ''data'', jsonb_build_object(''team_name'', v_team_name, ''tournament_name'', v_tournament_name)
  ));
  RETURN NEW;
END;
