      ''team_a'', v_team_a_name, ''team_b'', v_team_b_name,
      ''score_a'', v_score_a, ''score_b'', v_score_b,
      ''winner'', v_winner_name, ''tournament_name'', v_tournament_name,
      ''format'', NEW.format
    )
  ));
  RETURN NEW;
END;
